const input = $input.item.json;
const authData = $('Auth OK?').item.json;

let themeContent = '';
try {
  themeContent = input.content[0].text;
} catch(e) {
  themeContent = JSON.stringify(input);
}

let themes = [];
try {
  themes = JSON.parse(themeContent);
} catch(e) {
  const match = themeContent.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    themes = JSON.parse(match[0]);
  } else {
    themes = [{ error: 'Could not parse themes', raw: themeContent }];
  }
}

// Group into 4 weekly themes
const weeklyThemes = {};
for (const day of themes) {
  const weekNum = day.week_number || 1;
  if (!weeklyThemes[weekNum]) {
    weeklyThemes[weekNum] = {
      week_number: weekNum,
      theme_name: day.weekly_show_name || 'Week ' + weekNum,
      theme_description: '',
      show_concept: day.weekly_show_name || '',
      hook: day.hook || '',
      content_types: []
    };
  }
  weeklyThemes[weekNum].content_types.push({
    day_number: day.day_number,
    date: day.date,
    day_of_week: day.day_of_week,
    theme: day.theme,
    content_type: day.content_type,
    platform: day.platform,
    secondary_platform: day.secondary_platform,
    hook: day.hook,
    cta: day.cta,
    hashtags: Array.isArray(day.hashtags) ? day.hashtags.join(', ') : (day.hashtags || ''),
    notes: day.notes
  });
}

const month = authData.body?.month || new Date().toISOString().slice(0, 7);
const userId = authData.user_id;

return {
  json: {
    user_id: userId,
    month: month,
    weekly_themes: Object.values(weeklyThemes),
    raw_themes: themes
  }
};

const deleteResult = $input.item.json;
const parseData = $('Parse & Group Themes').item.json;
const campaignData = $('Supabase -- UPSERT Campaign').item.json;

const campaignId = Array.isArray(campaignData) ? campaignData[0].id : campaignData.id;
const userId = parseData.user_id;
const weeklyThemes = parseData.weekly_themes;

const themeRows = weeklyThemes.map(wt => ({
  user_id: userId,
  campaign_id: campaignId,
  week_number: wt.week_number,
  theme_name: wt.theme_name,
  theme_description: wt.theme_description || '',
  show_concept: wt.show_concept || '',
  hook: wt.hook || '',
  content_types: wt.content_types
}));

return { json: { theme_rows: themeRows, campaign_id: campaignId, user_id: userId } };
